        function showBillDetails(billId, billNumber) {
            $('#modalBillNumber').text(billNumber);

            let filteredItems = allItems.filter(i => i.billId === billId);

            let html = '';
            if (filteredItems.length > 0) {
                filteredItems.forEach(item => {
                    html += `<tr>
                        <td>${item.medicineName}</td>
                        <td>${item.quantity}</td>
                        <td>₹${item.unitPrice.toFixed(2)}</td>
                        <td>₹${item.totalPrice.toFixed(2)}</td>
                    </tr>`;
                });
            } else {
                html = `<tr><td colspan=""4"" class=""text-center text-muted"">No items found for this bill</td></tr>`;
            }

            $('#billItemsList').html(html);

            var modal = new bootstrap.Modal(document.getElementById('billItemsModal'));
